{
  "name": "GestureDraw Whiteboard",
  "description": "A high-performance, gesture-controlled digital whiteboard for teachers using MediaPipe Hand Tracking. Control markers, highlighters, and erasers with natural hand movements.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GestureState {
  IDLE = 'IDLE',
  MARKER = 'MARKER',
  HIGHLIGHTER = 'HIGHLIGHTER',
  ERASER = 'ERASER'
}

export interface Point {
  x: number;
  y: number;
}

export interface HandLandmark {
  x: number;
  y: number;
  z: number;
}

export interface Settings {
  markerColor: string;
  highlighterColor: string;
  brushSize: number;
  eraserSize: number;
}

import { HandLandmark, GestureState } from '../types';

/**
 * Calculates Euclidean distance between two 3D landmarks
 */
export const getDistance = (p1: HandLandmark, p2: HandLandmark): number => {
  return Math.sqrt(
    Math.pow(p1.x - p2.x, 2) + 
    Math.pow(p1.y - p2.y, 2) + 
    Math.pow(p1.z - p2.z, 2)
  );
};

/**
 * Determines if a specific finger is extended
 * Landmarks: Thumb(4), Index(8), Middle(12), Ring(16), Pinky(20)
 * MCPs: Thumb(2), Index(5), Middle(9), Ring(13), Pinky(17)
 */
export const isFingerUp = (landmarks: HandLandmark[], fingerIndex: number): boolean => {
  const tip = landmarks[fingerIndex * 4];
  const mcp = landmarks[fingerIndex * 4 - 2];
  // Simple check: tip is higher (lower y) than MCP
  // Note: Standard MediaPipe coordinates y=0 at top
  return tip.y < mcp.y;
};

/**
 * Main State Machine logic
 */
export const detectGesture = (landmarks: HandLandmark[]): GestureState => {
  if (!landmarks || landmarks.length === 0) return GestureState.IDLE;

  const thumbTip = landmarks[4];
  const indexTip = landmarks[8];
  const indexMCP = landmarks[5];
  const middleTip = landmarks[12];
  const middleMCP = landmarks[9];
  const ringTip = landmarks[16];
  const ringMCP = landmarks[13];
  const pinkyTip = landmarks[20];
  const pinkyMCP = landmarks[17];

  // Extension states
  const indexUp = indexTip.y < indexMCP.y;
  const middleUp = middleTip.y < middleMCP.y;
  const ringUp = ringTip.y < ringMCP.y;
  const pinkyUp = pinkyTip.y < pinkyMCP.y;

  // 1. Eraser: All fingers extended (Open Palm)
  if (indexUp && middleUp && ringUp && pinkyUp) {
    return GestureState.ERASER;
  }

  // 2. Highlighter: Index + Thumb pinch
  const pinchDist = getDistance(thumbTip, indexTip);
  if (pinchDist < 0.05) {
    return GestureState.HIGHLIGHTER;
  }

  // 3. Marker: ONLY Index finger extended
  if (indexUp && !middleUp && !ringUp && !pinkyUp) {
    return GestureState.MARKER;
  }

  return GestureState.IDLE;
};

import React from 'react';
import { Settings, GestureState } from '../types';

interface ControlPanelProps {
  settings: Settings;
  setSettings: React.Dispatch<React.SetStateAction<Settings>>;
  onClear: () => void;
  currentGesture: GestureState;
  fps: number;
}

const ControlPanel: React.FC<ControlPanelProps> = ({ 
  settings, 
  setSettings, 
  onClear, 
  currentGesture,
  fps
}) => {
  const handleChange = (key: keyof Settings, value: any) => {
    setSettings(prev => ({ ...prev, [key]: value }));
  };

  const getGestureColor = (state: GestureState) => {
    switch (state) {
      case GestureState.MARKER: return 'text-blue-600 font-bold';
      case GestureState.HIGHLIGHTER: return 'text-yellow-600 font-bold';
      case GestureState.ERASER: return 'text-red-600 font-bold';
      default: return 'text-gray-500';
    }
  };

  return (
    <div className="fixed top-6 right-6 w-72 glass-morphism rounded-2xl p-6 shadow-2xl z-50 flex flex-col gap-6 select-none animate-in fade-in slide-in-from-right-4 duration-500">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-bold text-gray-800">GestureDraw</h2>
        <span className="text-xs font-mono text-gray-500 bg-white/50 px-2 py-1 rounded">{fps} FPS</span>
      </div>

      <div className="space-y-4">
        {/* Status Indicator */}
        <div className="bg-white/40 p-3 rounded-xl border border-white/50">
          <p className="text-xs uppercase tracking-wider text-gray-500 mb-1">Current State</p>
          <p className={`text-lg ${getGestureColor(currentGesture)} transition-all duration-200`}>
            {currentGesture === GestureState.IDLE ? 'Hovering' : currentGesture}
          </p>
        </div>

        {/* Colors */}
        <div className="grid grid-cols-2 gap-3">
          <div className="flex flex-col gap-1">
            <label className="text-xs font-semibold text-gray-600">Marker</label>
            <input 
              type="color" 
              value={settings.markerColor}
              onChange={(e) => handleChange('markerColor', e.target.value)}
              className="w-full h-10 rounded-lg cursor-pointer bg-white/50 p-1 border border-white/80"
            />
          </div>
          <div className="flex flex-col gap-1">
            <label className="text-xs font-semibold text-gray-600">Highlighter</label>
            <input 
              type="color" 
              value={settings.highlighterColor}
              onChange={(e) => handleChange('highlighterColor', e.target.value)}
              className="w-full h-10 rounded-lg cursor-pointer bg-white/50 p-1 border border-white/80"
            />
          </div>
        </div>

        {/* Brush Size */}
        <div className="flex flex-col gap-2">
          <div className="flex justify-between">
            <label className="text-xs font-semibold text-gray-600">Brush Size</label>
            <span className="text-xs text-gray-500">{settings.brushSize}px</span>
          </div>
          <input 
            type="range" 
            min="1" 
            max="30" 
            value={settings.brushSize}
            onChange={(e) => handleChange('brushSize', parseInt(e.target.value))}
            className="w-full h-1.5 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
          />
        </div>

        {/* Eraser Size */}
        <div className="flex flex-col gap-2">
          <div className="flex justify-between">
            <label className="text-xs font-semibold text-gray-600">Eraser Radius</label>
            <span className="text-xs text-gray-500">{settings.eraserSize}px</span>
          </div>
          <input 
            type="range" 
            min="20" 
            max="100" 
            value={settings.eraserSize}
            onChange={(e) => handleChange('eraserSize', parseInt(e.target.value))}
            className="w-full h-1.5 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-red-500"
          />
        </div>
      </div>

      <button 
        onClick={onClear}
        className="w-full py-3 px-4 bg-white/80 hover:bg-white text-gray-800 font-bold rounded-xl shadow-sm border border-white/50 transition-all active:scale-95 flex items-center justify-center gap-2"
      >
        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-red-500" viewBox="0 0 20 20" fill="currentColor">
          <path fillRule="evenodd" d="M9 2a1 1 0 00-.894.553L7.382 4H4a1 1 0 000 2v10a2 2 0 002 2h8a2 2 0 002-2V6a1 1 0 100-2h-3.382l-.724-1.447A1 1 0 0011 2H9zM7 8a1 1 0 012 0v6a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v6a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" />
        </svg>
        Clear Whiteboard
      </button>

      <div className="text-[10px] text-gray-400 text-center space-y-1">
        <p>👆 Index Up: Marker</p>
        <p>🤏 Pinch: Highlighter</p>
        <p>🖐 Open Palm: Eraser</p>
      </div>
    </div>
  );
};

export default ControlPanel;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Settings, GestureState, Point } from './types';
import { detectGesture } from './utils/handLogic';
import ControlPanel from './components/ControlPanel';

// Load MediaPipe from CDN for easier consumption in this context
declare var Hands: any;
declare var Camera: any;

const App: React.FC = () => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null); // Feedback layer (cursor, skeleton)
  const drawRef = useRef<HTMLCanvasElement>(null);   // Persistent drawing layer
  const [settings, setSettings] = useState<Settings>({
    markerColor: '#2563eb',
    highlighterColor: '#facc15',
    brushSize: 5,
    eraserSize: 50,
  });
  const [gesture, setGesture] = useState<GestureState>(GestureState.IDLE);
  const [fps, setFps] = useState(0);

  // Drawing state
  const prevPointRef = useRef<Point | null>(null);
  const lastTimeRef = useRef<number>(performance.now());
  const framesRef = useRef<number>(0);

  /**
   * Clears the main drawing board
   */
  const clearBoard = useCallback(() => {
    const ctx = drawRef.current?.getContext('2d');
    if (ctx && drawRef.current) {
      ctx.clearRect(0, 0, drawRef.current.width, drawRef.current.height);
    }
  }, []);

  /**
   * Initializes the whiteboard and hand tracking
   */
  useEffect(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    const drawCanvas = drawRef.current;
    if (!video || !canvas || !drawCanvas) return;

    const ctx = canvas.getContext('2d');
    const dctx = drawCanvas.getContext('2d');
    if (!ctx || !dctx) return;

    // Load External Scripts for MediaPipe
    const scriptHands = document.createElement('script');
    scriptHands.src = "https://cdn.jsdelivr.net/npm/@mediapipe/hands/hands.js";
    scriptHands.async = true;

    const scriptCamera = document.createElement('script');
    scriptCamera.src = "https://cdn.jsdelivr.net/npm/@mediapipe/camera_utils/camera_utils.js";
    scriptCamera.async = true;

    document.head.appendChild(scriptHands);
    document.head.appendChild(scriptCamera);

    const onResults = (results: any) => {
      // FPS Calculation
      framesRef.current++;
      const now = performance.now();
      if (now - lastTimeRef.current > 1000) {
        setFps(Math.round((framesRef.current * 1000) / (now - lastTimeRef.current)));
        framesRef.current = 0;
        lastTimeRef.current = now;
      }

      // Sync canvas dimensions
      if (canvas.width !== video.videoWidth) {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        drawCanvas.width = video.videoWidth;
        drawCanvas.height = video.videoHeight;
      }

      // Clear feedback layer
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      if (results.multiHandLandmarks && results.multiHandLandmarks.length > 0) {
        const landmarks = results.multiHandLandmarks[0];
        const state = detectGesture(landmarks);
        setGesture(state);

        // Get finger tip coordinate
        const indexTip = landmarks[8];
        const thumbTip = landmarks[4];

        let targetX = indexTip.x * canvas.width;
        let targetY = indexTip.y * canvas.height;

        if (state === GestureState.HIGHLIGHTER) {
          // Use midpoint of pinch
          targetX = ((indexTip.x + thumbTip.x) / 2) * canvas.width;
          targetY = ((indexTip.y + thumbTip.y) / 2) * canvas.height;
        } else if (state === GestureState.ERASER) {
          // Use palm center
          const palm = landmarks[9];
          targetX = palm.x * canvas.width;
          targetY = palm.y * canvas.height;
        }

        const currentPoint: Point = { x: targetX, y: targetY };

        // Handle Drawing Logic
        if (state === GestureState.MARKER || state === GestureState.HIGHLIGHTER) {
          if (prevPointRef.current) {
            dctx.beginPath();
            dctx.lineCap = 'round';
            dctx.lineJoin = 'round';

            if (state === GestureState.MARKER) {
              dctx.strokeStyle = settings.markerColor;
              dctx.lineWidth = settings.brushSize;
              dctx.globalAlpha = 1.0;
            } else {
              dctx.strokeStyle = settings.highlighterColor;
              dctx.lineWidth = settings.brushSize * 4;
              dctx.globalAlpha = 0.5;
            }

            // Smooth interpolation (quadratic curve)
            const midX = (prevPointRef.current.x + currentPoint.x) / 2;
            const midY = (prevPointRef.current.y + currentPoint.y) / 2;

            dctx.moveTo(prevPointRef.current.x, prevPointRef.current.y);
            dctx.quadraticCurveTo(prevPointRef.current.x, prevPointRef.current.y, midX, midY);
            dctx.stroke();
          }
          prevPointRef.current = currentPoint;
        } else if (state === GestureState.ERASER) {
          dctx.save();
          dctx.globalCompositeOperation = 'destination-out';
          dctx.beginPath();
          dctx.arc(targetX, targetY, settings.eraserSize, 0, Math.PI * 2);
          dctx.fill();
          dctx.restore();
          prevPointRef.current = null;
        } else {
          prevPointRef.current = null;
        }

        // Draw Visual Indicators on feedback layer
        // Draw Cursor
        ctx.beginPath();
        ctx.arc(targetX, targetY, state === GestureState.ERASER ? settings.eraserSize : 8, 0, Math.PI * 2);
        ctx.strokeStyle = 'white';
        ctx.lineWidth = 2;
        ctx.stroke();

        if (state === GestureState.ERASER) {
          ctx.fillStyle = 'rgba(255, 0, 0, 0.1)';
          ctx.fill();
        } else {
          ctx.fillStyle = state === GestureState.MARKER ? settings.markerColor : settings.highlighterColor;
          ctx.fill();
        }
      } else {
        setGesture(GestureState.IDLE);
        prevPointRef.current = null;
      }
    };

    const initMediaPipe = () => {
      const hands = new Hands({
        locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/hands/${file}`
      });

      hands.setOptions({
        maxNumHands: 1,
        modelComplexity: 1,
        minDetectionConfidence: 0.7,
        minTrackingConfidence: 0.7
      });

      hands.onResults(onResults);

      const camera = new Camera(video, {
        onFrame: async () => {
          await hands.send({ image: video });
        },
        width: 1280,
        height: 720
      });

      camera.start();
    };

    const checkScripts = setInterval(() => {
      if (typeof Hands !== 'undefined' && typeof Camera !== 'undefined') {
        clearInterval(checkScripts);
        initMediaPipe();
      }
    }, 200);

    return () => {
      clearInterval(checkScripts);
      // Cleanup if needed
    };
  }, [settings]);

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-black flex items-center justify-center">
      {/* Background Video (Mirrored) */}
      <video 
        ref={videoRef}
        className="absolute inset-0 w-full h-full object-cover mirror opacity-40 grayscale-[20%]"
        playsInline
        muted
      />

      {/* Main Drawing Layer (Persistent) */}
      <canvas 
        ref={drawRef}
        className="absolute inset-0 w-full h-full mirror z-10"
      />

      {/* Feedback Layer (Cursor, Indicators) */}
      <canvas 
        ref={canvasRef}
        className="absolute inset-0 w-full h-full mirror z-20 pointer-events-none"
      />

      {/* UI Controls */}
      <ControlPanel 
        settings={settings}
        setSettings={setSettings}
        onClear={clearBoard}
        currentGesture={gesture}
        fps={fps}
      />

      {/* Tutorial Overlay (Visible only on start if desired) */}
      {gesture === GestureState.IDLE && (
        <div className="absolute bottom-10 left-1/2 -translate-x-1/2 z-30 bg-black/50 backdrop-blur-md px-6 py-3 rounded-full border border-white/20 text-white animate-bounce">
          👋 Raise your hand to start drawing
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Settings, GestureState } from '../types';

interface ControlPanelProps {
  settings: Settings;
  setSettings: React.Dispatch<React.SetStateAction<Settings>>;
  onClear: () => void;
  currentGesture: GestureState;
  fps: number;
}

