          <div className="flex justify-between items-center border-b border-black/10 pb-3">
            <h2 className="text-lg font-bold text-gray-800">Settings</h2>
            <span className="text-[10px] font-mono text-gray-500 bg-white/50 px-1.5 py-0.5 rounded">{fps} FPS</span>
          </div>

          <div className="space-y-4">
            {/* Status Indicator */}
            <div className="bg-white/40 p-3 rounded-xl border border-white/50">
              <p className="text-[10px] uppercase tracking-wider text-gray-500 mb-0.5">Active Gesture</p>
              <p className={`text-md ${getGestureColor(currentGesture)} transition-all duration-200`}>
                {currentGesture === GestureState.IDLE ? 'Hovering' : currentGesture}
              </p>
            </div>

            {/* Colors */}
            <div className="grid grid-cols-2 gap-3">
              <div className="flex flex-col gap-1">
                <label className="text-xs font-semibold text-gray-600">Marker</label>
                <input 
                  type="color" 
                  value={settings.markerColor}
                  onChange={(e) => handleChange('markerColor', e.target.value)}
                  className="w-full h-8 rounded-md cursor-pointer bg-white/50 p-0.5 border border-white/80"
                />
              </div>
              <div className="flex flex-col gap-1">
                <label className="text-xs font-semibold text-gray-600">Highlighter</label>
                <input 
