          >
            Clear Board
          </button>

          <div className="text-[10px] text-gray-400 text-center space-y-1 pt-2 border-t border-black/5">
            <p>👆 Index: Draw | 🤏 Pinch: Highlit</p>
            <p>🖐 Palm: Rect Eraser</p>
          </div>
        </div>
      )}
    </div>
  );
};

