    eraserSize: 60,
  });
  const [gesture, setGesture] = useState<GestureState>(GestureState.IDLE);
  const [fps, setFps] = useState(0);

  // Smoothing and Drawing state
  const prevPointRef = useRef<Point | null>(null);
  const lastMidPointRef = useRef<Point | null>(null);
  const smoothedPointRef = useRef<Point | null>(null);
  const lastTimeRef = useRef<number>(performance.now());
  const framesRef = useRef<number>(0);

  // EMA smoothing factor (0 to 1). Lower is smoother but has more lag.
  const SMOOTHING_FACTOR = 0.35;

  /**
   * Clears the main drawing board
   */
  const clearBoard = useCallback(() => {
    const ctx = drawRef.current?.getContext('2d');
    if (ctx && drawRef.current) {
      ctx.clearRect(0, 0, drawRef.current.width, drawRef.current.height);
    }
  }, []);

  /**
   * Initializes the whiteboard and hand tracking
   */
  useEffect(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    const drawCanvas = drawRef.current;
    if (!video || !canvas || !drawCanvas) return;

    const ctx = canvas.getContext('2d');
    const dctx = drawCanvas.getContext('2d');
    if (!ctx || !dctx) return;

    // Load External Scripts for MediaPipe
    const scriptHands = document.createElement('script');
    scriptHands.src = "https://cdn.jsdelivr.net/npm/@mediapipe/hands/hands.js";
    scriptHands.async = true;

    const scriptCamera = document.createElement('script');
    scriptCamera.src = "https://cdn.jsdelivr.net/npm/@mediapipe/camera_utils/camera_utils.js";
    scriptCamera.async = true;

    document.head.appendChild(scriptHands);
    document.head.appendChild(scriptCamera);

    const onResults = (results: any) => {
      // FPS Calculation
      framesRef.current++;
      const now = performance.now();
      if (now - lastTimeRef.current > 1000) {
        setFps(Math.round((framesRef.current * 1000) / (now - lastTimeRef.current)));
        framesRef.current = 0;
        lastTimeRef.current = now;
      }

      // Sync canvas dimensions
      if (canvas.width !== video.videoWidth) {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        drawCanvas.width = video.videoWidth;
        drawCanvas.height = video.videoHeight;
      }

      // Clear feedback layer
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      if (results.multiHandLandmarks && results.multiHandLandmarks.length > 0) {
        const landmarks = results.multiHandLandmarks[0];
        const state = detectGesture(landmarks);
        setGesture(state);

        // Get raw target coordinate
        const indexTip = landmarks[8];
        const thumbTip = landmarks[4];

        let rawX = indexTip.x * canvas.width;
        let rawY = indexTip.y * canvas.height;

        if (state === GestureState.HIGHLIGHTER) {
          rawX = ((indexTip.x + thumbTip.x) / 2) * canvas.width;
          rawY = ((indexTip.y + thumbTip.y) / 2) * canvas.height;
        } else if (state === GestureState.ERASER) {
          const palm = landmarks[9];
          rawX = palm.x * canvas.width;
          rawY = palm.y * canvas.height;
        }

        // Apply Exponential Moving Average (EMA) smoothing to reduce jitter
        if (!smoothedPointRef.current) {
          smoothedPointRef.current = { x: rawX, y: rawY };
        } else {
          smoothedPointRef.current.x = smoothedPointRef.current.x + (rawX - smoothedPointRef.current.x) * SMOOTHING_FACTOR;
          smoothedPointRef.current.y = smoothedPointRef.current.y + (rawY - smoothedPointRef.current.y) * SMOOTHING_FACTOR;
        }

        const currentPoint = { ...smoothedPointRef.current };

        // Handle Drawing Logic
        if (state === GestureState.MARKER || state === GestureState.HIGHLIGHTER) {
          if (prevPointRef.current) {
            const midPoint = {
              x: (prevPointRef.current.x + currentPoint.x) / 2,
              y: (prevPointRef.current.y + currentPoint.y) / 2
            };

            dctx.beginPath();
            dctx.lineCap = 'round';
            dctx.lineJoin = 'round';

            if (state === GestureState.MARKER) {
              dctx.strokeStyle = settings.markerColor;
              dctx.lineWidth = settings.brushSize;
              dctx.globalAlpha = 1.0;
            } else {
              dctx.strokeStyle = settings.highlighterColor;
              dctx.lineWidth = settings.brushSize * 4;
              dctx.globalAlpha = 0.5;
            }

            // If we have a previous midPoint, draw curve from that to new midPoint
            // using the previous raw point as the control point for perfect continuity.
            if (lastMidPointRef.current) {
              dctx.moveTo(lastMidPointRef.current.x, lastMidPointRef.current.y);
              dctx.quadraticCurveTo(prevPointRef.current.x, prevPointRef.current.y, midPoint.x, midPoint.y);
              dctx.stroke();
            } else {
              // First segment of a stroke
              dctx.moveTo(prevPointRef.current.x, prevPointRef.current.y);
              dctx.lineTo(midPoint.x, midPoint.y);
              dctx.stroke();
            }

            lastMidPointRef.current = midPoint;
          }
          prevPointRef.current = currentPoint;
        } else if (state === GestureState.ERASER) {
          const eWidth = settings.eraserSize * 0.7;
          const eHeight = settings.eraserSize * 1.2;

          dctx.save();
          dctx.globalCompositeOperation = 'destination-out';
          dctx.fillStyle = 'rgba(255, 255, 255, 1)';
          dctx.fillRect(currentPoint.x - eWidth / 2, currentPoint.y - eHeight / 2, eWidth, eHeight);
          dctx.restore();

          prevPointRef.current = null;
          lastMidPointRef.current = null;
        } else {
          prevPointRef.current = null;
          lastMidPointRef.current = null;
        }

        // Draw Visual Indicators on feedback layer
        if (state === GestureState.ERASER) {
          const eWidth = settings.eraserSize * 0.7;
          const eHeight = settings.eraserSize * 1.2;
          ctx.strokeStyle = 'white';
          ctx.lineWidth = 2;
          ctx.strokeRect(currentPoint.x - eWidth / 2, currentPoint.y - eHeight / 2, eWidth, eHeight);
          ctx.fillStyle = 'rgba(255, 255, 255, 0.2)';
          ctx.fillRect(currentPoint.x - eWidth / 2, currentPoint.y - eHeight / 2, eWidth, eHeight);
        } else {
          ctx.beginPath();
          ctx.arc(currentPoint.x, currentPoint.y, state === GestureState.IDLE ? 6 : settings.brushSize * 1.5, 0, Math.PI * 2);
          ctx.strokeStyle = 'white';
          ctx.lineWidth = 2;
          ctx.stroke();
          ctx.fillStyle = state === GestureState.MARKER ? settings.markerColor : settings.highlighterColor;
          if (state === GestureState.IDLE) ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
          ctx.fill();
        }
      } else {
        setGesture(GestureState.IDLE);
        prevPointRef.current = null;
        lastMidPointRef.current = null;
        smoothedPointRef.current = null;
      }
    };

    const initMediaPipe = () => {
      const hands = new Hands({
        locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/hands/${file}`
      });

      hands.setOptions({
        maxNumHands: 1,
        modelComplexity: 1,
        minDetectionConfidence: 0.7,
        minTrackingConfidence: 0.7
      });

      hands.onResults(onResults);

      const camera = new Camera(video, {
        onFrame: async () => {
          await hands.send({ image: video });
        },
        width: 1280,
        height: 720
      });

      camera.start();
    };

    const checkScripts = setInterval(() => {
      if (typeof Hands !== 'undefined' && typeof Camera !== 'undefined') {
        clearInterval(checkScripts);
        initMediaPipe();
      }
    }, 200);

    return () => {
      clearInterval(checkScripts);
    };
  }, [settings]);

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-black flex items-center justify-center">
      {/* Background Video (Mirrored) */}
      <video 
        ref={videoRef}
        className="absolute inset-0 w-full h-full object-cover mirror opacity-30 grayscale-[40%]"
        playsInline
        muted
      />

      {/* Main Drawing Layer (Persistent) */}
      <canvas 
        ref={drawRef}
        className="absolute inset-0 w-full h-full mirror z-10"
      />

      {/* Feedback Layer (Cursor, Indicators) */}
      <canvas 
        ref={canvasRef}
        className="absolute inset-0 w-full h-full mirror z-20 pointer-events-none"
      />

      {/* UI Controls */}
      <ControlPanel 
        settings={settings}
        setSettings={setSettings}
        onClear={clearBoard}
        currentGesture={gesture}
        fps={fps}
      />

      {/* Minimal Status (Bottom Left) */}
      <div className="absolute bottom-6 left-6 z-30 flex flex-col gap-1 pointer-events-none">
        <div className={`px-4 py-1.5 rounded-full glass-morphism text-xs font-bold tracking-widest uppercase transition-all duration-300 ${gesture !== GestureState.IDLE ? 'opacity-100' : 'opacity-40'}`}>
          Mode: {gesture}
