  const [gesture, setGesture] = useState<GestureState>(GestureState.IDLE);
  const [fps, setFps] = useState(0);

  // Per-hand state tracking for smooth, multi-hand drawing
  const prevPoints = useRef<{ [key: string]: Point | null }>({ Left: null, Right: null });
  const lastMidPoints = useRef<{ [key: string]: Point | null }>({ Left: null, Right: null });
  const smoothedPoints = useRef<{ [key: string]: Point | null }>({ Left: null, Right: null });

  const lastTimeRef = useRef<number>(performance.now());
  const framesRef = useRef<number>(0);

  // EMA smoothing factor (0 to 1). Lower is smoother but has more lag.
  const SMOOTHING_FACTOR = 0.35;

  const clearBoard = useCallback(() => {
    const ctx = drawRef.current?.getContext('2d');
    if (ctx && drawRef.current) {
      ctx.clearRect(0, 0, drawRef.current.width, drawRef.current.height);
    }
  }, []);

  useEffect(() => {
    const video = videoRef.current;
    const canvas = canvasRef.current;
    const drawCanvas = drawRef.current;
    if (!video || !canvas || !drawCanvas) return;

    const ctx = canvas.getContext('2d');
    const dctx = drawCanvas.getContext('2d');
    if (!ctx || !dctx) return;

    // Load External Scripts for MediaPipe
    const scriptHands = document.createElement('script');
    scriptHands.src = "https://cdn.jsdelivr.net/npm/@mediapipe/hands/hands.js";
    scriptHands.async = true;

    const scriptCamera = document.createElement('script');
    scriptCamera.src = "https://cdn.jsdelivr.net/npm/@mediapipe/camera_utils/camera_utils.js";
    scriptCamera.async = true;

    document.head.appendChild(scriptHands);
    document.head.appendChild(scriptCamera);

    const onResults = (results: any) => {
      // FPS Calculation
      framesRef.current++;
      const now = performance.now();
      if (now - lastTimeRef.current > 1000) {
        setFps(Math.round((framesRef.current * 1000) / (now - lastTimeRef.current)));
        framesRef.current = 0;
        lastTimeRef.current = now;
      }

      // Sync canvas dimensions
      if (canvas.width !== video.videoWidth) {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        drawCanvas.width = video.videoWidth;
        drawCanvas.height = video.videoHeight;
      }

      // Clear feedback layer
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      const activeHandLabels = new Set<string>();

      if (results.multiHandLandmarks && results.multiHandLandmarks.length > 0) {
        results.multiHandLandmarks.forEach((landmarks: any, index: number) => {
          const handedness = results.multiHandedness[index];
          const label = handedness.label; // 'Left' or 'Right'
          activeHandLabels.add(label);

          const rawState = detectGesture(landmarks);
          let validState = GestureState.IDLE;

          // Logic: Right = Marker, Left = Highlighter, Either = Eraser
          if (rawState === GestureState.ERASER) {
            validState = GestureState.ERASER;
          } else if (label === 'Right' && rawState === GestureState.MARKER) {
            validState = GestureState.MARKER;
          } else if (label === 'Left' && rawState === GestureState.HIGHLIGHTER) {
            validState = GestureState.HIGHLIGHTER;
          }

          if (validState !== GestureState.IDLE) {
            setGesture(validState);
          }

          // Calculate target coordinate
          const indexTip = landmarks[8];
          const thumbTip = landmarks[4];
          let rawX = indexTip.x * canvas.width;
          let rawY = indexTip.y * canvas.height;

          if (validState === GestureState.HIGHLIGHTER) {
            rawX = ((indexTip.x + thumbTip.x) / 2) * canvas.width;
            rawY = ((indexTip.y + thumbTip.y) / 2) * canvas.height;
          } else if (validState === GestureState.ERASER) {
            const palm = landmarks[9];
            rawX = palm.x * canvas.width;
            rawY = palm.y * canvas.height;
          }

          // Apply smoothing per hand
          let smoothed = smoothedPoints.current[label];
          if (!smoothed) {
            smoothed = { x: rawX, y: rawY };
          } else {
            smoothed.x = smoothed.x + (rawX - smoothed.x) * SMOOTHING_FACTOR;
            smoothed.y = smoothed.y + (rawY - smoothed.y) * SMOOTHING_FACTOR;
          }
          smoothedPoints.current[label] = smoothed;

          const currentPoint = { ...smoothed };

          // Draw logic
          if (validState === GestureState.MARKER || validState === GestureState.HIGHLIGHTER) {
            const prev = prevPoints.current[label];
            const lastMid = lastMidPoints.current[label];

            if (prev) {
              const midPoint = {
                x: (prev.x + currentPoint.x) / 2,
                y: (prev.y + currentPoint.y) / 2
              };

              dctx.beginPath();
              dctx.lineCap = 'round';
              dctx.lineJoin = 'round';

              if (validState === GestureState.MARKER) {
                dctx.strokeStyle = settings.markerColor;
                dctx.lineWidth = settings.brushSize;
                dctx.globalAlpha = 1.0;
              } else {
                dctx.strokeStyle = settings.highlighterColor;
                dctx.lineWidth = settings.brushSize * 4;
                dctx.globalAlpha = 0.5;
              }

              if (lastMid) {
                dctx.moveTo(lastMid.x, lastMid.y);
                dctx.quadraticCurveTo(prev.x, prev.y, midPoint.x, midPoint.y);
                dctx.stroke();
              } else {
                dctx.moveTo(prev.x, prev.y);
                dctx.lineTo(midPoint.x, midPoint.y);
                dctx.stroke();
              }
              lastMidPoints.current[label] = midPoint;
            }
            prevPoints.current[label] = currentPoint;
          } else if (validState === GestureState.ERASER) {
            const eWidth = settings.eraserSize * 0.7;
            const eHeight = settings.eraserSize * 1.2;
            dctx.save();
            dctx.globalCompositeOperation = 'destination-out';
            dctx.fillStyle = 'white';
            dctx.fillRect(currentPoint.x - eWidth / 2, currentPoint.y - eHeight / 2, eWidth, eHeight);
            dctx.restore();
            prevPoints.current[label] = null;
            lastMidPoints.current[label] = null;
          } else {
            prevPoints.current[label] = null;
            lastMidPoints.current[label] = null;
          }

          // Visual Cursor per hand
          if (validState === GestureState.ERASER) {
            const eWidth = settings.eraserSize * 0.7;
            const eHeight = settings.eraserSize * 1.2;
            ctx.strokeStyle = 'white';
            ctx.lineWidth = 2;
            ctx.strokeRect(currentPoint.x - eWidth / 2, currentPoint.y - eHeight / 2, eWidth, eHeight);
            ctx.fillStyle = 'rgba(255, 255, 255, 0.2)';
            ctx.fillRect(currentPoint.x - eWidth / 2, currentPoint.y - eHeight / 2, eWidth, eHeight);
          } else {
            ctx.beginPath();
            ctx.arc(currentPoint.x, currentPoint.y, validState === GestureState.IDLE ? 6 : settings.brushSize * 1.5, 0, Math.PI * 2);
            ctx.strokeStyle = 'white';
            ctx.lineWidth = 2;
            ctx.stroke();
            ctx.fillStyle = label === 'Right' ? settings.markerColor : settings.highlighterColor;
            if (validState === GestureState.IDLE) ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
            ctx.fill();

            // Text Label for hand role
            ctx.fillStyle = 'white';
            ctx.font = 'bold 10px sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText(label === 'Right' ? 'MARKER' : 'HIGHLIGHT', currentPoint.x, currentPoint.y - 15);
          }
        });
      }

      // Cleanup points for hands that disappeared
      ['Left', 'Right'].forEach(side => {
        if (!activeHandLabels.has(side)) {
          prevPoints.current[side] = null;
          lastMidPoints.current[side] = null;
          smoothedPoints.current[side] = null;
        }
      });

      if (activeHandLabels.size === 0) {
        setGesture(GestureState.IDLE);
      }
    };

    const initMediaPipe = () => {
      const hands = new Hands({
        locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/hands/${file}`
      });

      hands.setOptions({
        maxNumHands: 2, // Enable two hands tracking
        modelComplexity: 1,
        minDetectionConfidence: 0.7,
        minTrackingConfidence: 0.7
      });

      hands.onResults(onResults);

      const camera = new Camera(video, {
        onFrame: async () => {
          await hands.send({ image: video });
        },
        width: 1280,
        height: 720
      });

      camera.start();
    };

    const checkScripts = setInterval(() => {
      if (typeof Hands !== 'undefined' && typeof Camera !== 'undefined') {
        clearInterval(checkScripts);
        initMediaPipe();
      }
    }, 200);

    return () => clearInterval(checkScripts);
  }, [settings]);

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-black flex items-center justify-center">
      <video 
        ref={videoRef}
        className="absolute inset-0 w-full h-full object-cover mirror opacity-30 grayscale-[40%]"
        playsInline
        muted
      />
      <canvas ref={drawRef} className="absolute inset-0 w-full h-full mirror z-10" />
      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full mirror z-20 pointer-events-none" />

      <ControlPanel 
        settings={settings}
        setSettings={setSettings}
        onClear={clearBoard}
        currentGesture={gesture}
        fps={fps}
      />

      <div className="absolute bottom-6 left-6 z-30 flex flex-col gap-1 pointer-events-none">
        <div className={`px-4 py-1.5 rounded-full glass-morphism text-xs font-bold tracking-widest uppercase transition-all duration-300 ${gesture !== GestureState.IDLE ? 'opacity-100' : 'opacity-40'}`}>
          Active: {gesture}
        </div>
      </div>

      {gesture === GestureState.IDLE && (
        <div className="absolute bottom-20 left-1/2 -translate-x-1/2 z-30 bg-black/40 backdrop-blur-md px-8 py-4 rounded-3xl border border-white/10 text-white animate-pulse text-sm">
          👋 Right: Marker | Left: Highlighter | 🖐 Palm: Erase
        </div>
      )}
    </div>
  );
};

