import { HandLandmark, GestureState } from '../types';

/**
 * Calculates Euclidean distance between two 3D landmarks
 */
export const getDistance = (p1: HandLandmark, p2: HandLandmark): number => {
  return Math.sqrt(
    Math.pow(p1.x - p2.x, 2) + 
    Math.pow(p1.y - p2.y, 2) + 
    Math.pow(p1.z - p2.z, 2)
  );
};

/**
 * Main State Machine logic
 */
export const detectGesture = (landmarks: HandLandmark[]): GestureState => {
  if (!landmarks || landmarks.length === 0) return GestureState.IDLE;

  const indexTip = landmarks[8];
  const indexMCP = landmarks[5];
  const middleTip = landmarks[12];
  const middleMCP = landmarks[9];
  const ringTip = landmarks[16];
  const ringMCP = landmarks[13];
  const pinkyTip = landmarks[20];
  const pinkyMCP = landmarks[17];

  // Extension states (tip is higher/lower-y than MCP)
  const indexUp = indexTip.y < indexMCP.y;
  const middleUp = middleTip.y < middleMCP.y;
  const ringUp = ringTip.y < ringMCP.y;
  const pinkyUp = pinkyTip.y < pinkyMCP.y;

  // 1. Eraser: All 4 main fingers extended (Open Palm)
  if (indexUp && middleUp && ringUp && pinkyUp) {
    return GestureState.ERASER;
  }

  // 2. Highlighter: Index AND Middle fingers extended (Peace sign / V)
  if (indexUp && middleUp && !ringUp && !pinkyUp) {
    return GestureState.HIGHLIGHTER;
  }

  // 3. Marker: ONLY Index finger extended
  if (indexUp && !middleUp && !ringUp && !pinkyUp) {
    return GestureState.MARKER;
  }

  return GestureState.IDLE;
};

